#!/usr/bin/env python3
"""
Restore the CF header token icon as the original transparent PNG.

The current branch imports cf-token.svg, but all committed copies of that SVG
are empty. This script:
- writes frontend/src/static/images/wallet/cf-token.png;
- changes HeaderRight.jsx to import the PNG;
- removes the empty source/generated SVG duplicates.

Usage from the repository root:
    python3 fix-cf-token-icon.py --check
    python3 fix-cf-token-icon.py
"""

from __future__ import annotations

import argparse
import base64
import os
import sys
from pathlib import Path


HEADER_PATH = Path(
    "frontend/src/static/js/components/page-layout/PageHeader/HeaderRight.jsx"
)
PNG_PATH = Path("frontend/src/static/images/wallet/cf-token.png")
SVG_PATHS = (
    Path("frontend/src/static/images/wallet/cf-token.svg"),
    Path("static/images/wallet/cf-token.svg"),
    Path("static/static/images/wallet/cf-token.svg"),
)

OLD_IMPORT = "import cfTokenIcon from '../../../../images/wallet/cf-token.svg';"
NEW_IMPORT = "import cfTokenIcon from '../../../../images/wallet/cf-token.png';"

PNG_BASE64 = """"""


def fail(message: str) -> None:
    print(f"ERROR: {message}", file=sys.stderr)
    raise SystemExit(1)


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument(
        "--check",
        action="store_true",
        help="Validate and report changes without writing files.",
    )
    args = parser.parse_args()

    if not HEADER_PATH.is_file():
        fail(f"Run this script from the repository root; missing {HEADER_PATH}")

    header_old = HEADER_PATH.read_text(encoding="utf-8")

    if OLD_IMPORT in header_old:
        header_new = header_old.replace(OLD_IMPORT, NEW_IMPORT, 1)
    elif NEW_IMPORT in header_old:
        header_new = header_old
    else:
        fail(
            "Could not find the cfTokenIcon import in HeaderRight.jsx. "
            f"Run: grep -n 'cfTokenIcon' {HEADER_PATH}"
        )

    png_bytes = base64.b64decode(PNG_BASE64)
    png_changed = not PNG_PATH.is_file() or PNG_PATH.read_bytes() != png_bytes
    header_changed = header_new != header_old
    svg_existing = [path for path in SVG_PATHS if path.exists()]

    if not header_changed and not png_changed and not svg_existing:
        print("CF token icon fix is already applied.")
        return

    if args.check:
        print("Check passed.")
        if header_changed:
            print(f"Would update: {HEADER_PATH}")
        if png_changed:
            print(f"Would create/update: {PNG_PATH}")
        for path in svg_existing:
            print(f"Would remove: {path}")
        return

    header_mode = HEADER_PATH.stat().st_mode
    png_old = PNG_PATH.read_bytes() if PNG_PATH.is_file() else None
    svg_backups = {
        path: path.read_bytes()
        for path in svg_existing
        if path.is_file()
    }

    try:
        if header_changed:
            HEADER_PATH.write_text(header_new, encoding="utf-8")
            os.chmod(HEADER_PATH, header_mode)

        PNG_PATH.parent.mkdir(parents=True, exist_ok=True)
        PNG_PATH.write_bytes(png_bytes)

        for path in svg_existing:
            if path.is_file() or path.is_symlink():
                path.unlink()
    except Exception:
        HEADER_PATH.write_text(header_old, encoding="utf-8")
        os.chmod(HEADER_PATH, header_mode)

        if png_old is None:
            try:
                PNG_PATH.unlink()
            except FileNotFoundError:
                pass
        else:
            PNG_PATH.parent.mkdir(parents=True, exist_ok=True)
            PNG_PATH.write_bytes(png_old)

        for path, content in svg_backups.items():
            path.parent.mkdir(parents=True, exist_ok=True)
            path.write_bytes(content)

        raise

    print("CF token icon fix applied.")
    if header_changed:
        print(f"Updated: {HEADER_PATH}")
    if png_changed:
        print(f"Created/updated: {PNG_PATH}")
    for path in svg_existing:
        print(f"Removed: {path}")


if __name__ == "__main__":
    main()
